@property --scrollbar-color {
  syntax: "<color>";
  inherits: true;
  initial-value: transparent;
}

@property --scrollbar-size {
  syntax: "<length>";
  inherits: true;
  initial-value: 7px;
}

@property --scroll-fade-mask-size {
  syntax: "<length>";
  inherits: false;
  initial-value: 32px;
}

@property --scroll-fade-scrollbar-size {
  syntax: "<length>";
  inherits: false;
  initial-value: 0px;
}

