  syntax: "<length>";
  inherits: false;
  initial-value: 0px;
}

@utility scrollable {
  overflow: auto;
  scrollbar-width: thin;
  scrollbar-color: var(--scrollbar-color) transparent;
  transition: scrollbar-color 160ms;

  &::-webkit-scrollbar {
    border-radius: 8px;
    width: var(--scrollbar-size);
    height: var(--scrollbar-size);
    background: transparent;
  }

  &::-webkit-scrollbar-thumb {
    border-radius: 8px;
    background: var(--scrollbar-color);
  }

  &::-webkit-scrollbar-corner {
    background-color: transparent;
  }

  /* Hide the scrollbar until the element is interacted with. Add the
     companion `scrollable-always` class to force the bar to stay visible. */
  &:not(.scrollable-always):not(:hover):not(:focus):not(:focus-within):not(:active) {
    scrollbar-color: transparent transparent;
  }

  /* scrollbar-color inherits; reset on children with :where so a nested
     .scrollable can still override without escalating specificity. */
  & > :where(*) {
    scrollbar-color: var(--scrollbar-color) transparent;
  }
}

@utility scrollable-no-transition {
  transition: none;
}

@utility scroll-fade {
  @supports (scrollbar-width: thin) {
    --scroll-fade-scrollbar-size: 11px;
  }

  @supports (animation-timeline: scroll()) {
    contain: layout paint style;
    will-change: scroll-position, mask;
    mask-image:
      linear-gradient(
        to bottom,
        black 0,
        black var(--scroll-fade-block-padding-start),
        transparent var(--scroll-fade-block-padding-start),
        black calc(var(--scroll-fade-block-padding-start) + var(--scroll-fade-top-mask-size)),
        black calc(100% - var(--scroll-fade-block-padding-end) - var(--scroll-fade-bottom-mask-size)),
        transparent calc(100% - var(--scroll-fade-block-padding-end)),
        black calc(100% - var(--scroll-fade-block-padding-end)),
        black 100%
      ),
      linear-gradient(to left, black var(--scroll-fade-scrollbar-size), transparent var(--scroll-fade-scrollbar-size));
    mask-composite: add;
    mask-size:
      calc(100% - var(--scroll-fade-scrollbar-size)) 100%,
      100% 100%;
    mask-repeat: no-repeat;
    mask-position:
      top left,
      top right;
    animation:
      scroll-fade-top,
      scroll-fade-bottom reverse;
    animation-fill-mode: both;
    animation-timeline: scroll(self);
    animation-range:
      0 var(--scroll-fade-mask-size),
      calc(100% - var(--scroll-fade-mask-size)) 100%;
    animation-duration: 0.1s;
  }
}

@utility scroll-fade-inline {
  @supports (scrollbar-width: thin) {
    --scroll-fade-scrollbar-size: 11px;
  }

  @supports (animation-timeline: scroll()) {
    contain: layout paint style;
    will-change: scroll-position, mask;
    mask-image:
      linear-gradient(
        to right,
        black 0,
        black var(--scroll-fade-inline-padding-start),
        transparent var(--scroll-fade-inline-padding-start),
        black calc(var(--scroll-fade-inline-padding-start) + var(--scroll-fade-left-mask-size)),
        black calc(100% - var(--scroll-fade-inline-padding-end) - var(--scroll-fade-right-mask-size)),
        transparent calc(100% - var(--scroll-fade-inline-padding-end)),
        black calc(100% - var(--scroll-fade-inline-padding-end)),
        black 100%
      ),
      linear-gradient(to top, black var(--scroll-fade-scrollbar-size), transparent var(--scroll-fade-scrollbar-size));
    mask-composite: add;
    mask-size:
      100% calc(100% - var(--scroll-fade-scrollbar-size)),
      100% 100%;
    mask-repeat: no-repeat;
    mask-position:
      top left,
      bottom left;
    animation:
      scroll-fade-left,
      scroll-fade-right reverse;
    animation-fill-mode: both;
    animation-timeline: scroll(self inline);
    animation-range:
      0 var(--scroll-fade-mask-size),
      calc(100% - var(--scroll-fade-mask-size)) 100%;
    animation-duration: 0.1s;
  }
}

@utility scroll-fade-both {
  @supports (scrollbar-width: thin) {
    --scroll-fade-scrollbar-size: 11px;
  }

  @supports (animation-timeline: scroll()) {
    contain: layout paint style;
    will-change: scroll-position, mask;
    mask-image:
      linear-gradient(
        to left,
        black var(--scroll-fade-block-scrollbar-size),
        transparent var(--scroll-fade-block-scrollbar-size)
      ),
      linear-gradient(
        to top,
        black var(--scroll-fade-inline-scrollbar-size),
        transparent var(--scroll-fade-inline-scrollbar-size)
      ),
      linear-gradient(
        to bottom,
        black 0,
        black var(--scroll-fade-block-padding-start),
        transparent var(--scroll-fade-block-padding-start),
        black calc(var(--scroll-fade-block-padding-start) + var(--scroll-fade-top-mask-size)),
        black calc(100% - var(--scroll-fade-block-padding-end) - var(--scroll-fade-bottom-mask-size)),
        transparent calc(100% - var(--scroll-fade-block-padding-end)),
        black calc(100% - var(--scroll-fade-block-padding-end)),
        black 100%
      ),
      linear-gradient(
        to right,
        black 0,
        black var(--scroll-fade-inline-padding-start),
        transparent var(--scroll-fade-inline-padding-start),
        black calc(var(--scroll-fade-inline-padding-start) + var(--scroll-fade-left-mask-size)),
        black calc(100% - var(--scroll-fade-inline-padding-end) - var(--scroll-fade-right-mask-size)),
        transparent calc(100% - var(--scroll-fade-inline-padding-end)),
        black calc(100% - var(--scroll-fade-inline-padding-end)),
        black 100%
      );
    mask-composite: add, add, intersect;
    mask-size:
      100% 100%,
      100% 100%,
      calc(100% - var(--scroll-fade-block-scrollbar-size)) calc(100% - var(--scroll-fade-inline-scrollbar-size)),
      calc(100% - var(--scroll-fade-block-scrollbar-size)) calc(100% - var(--scroll-fade-inline-scrollbar-size));
    mask-repeat: no-repeat;
    mask-position:
      top right,
      bottom left,
      top left,
      top left;
    animation:
      scroll-fade-top,
      scroll-fade-bottom reverse,
      scroll-fade-left,
      scroll-fade-right reverse,
      scroll-fade-has-block-scroll,
      scroll-fade-has-inline-scroll;
    animation-fill-mode: both;
    animation-timeline:
      scroll(self), scroll(self), scroll(self inline), scroll(self inline), scroll(self), scroll(self inline);
    animation-range:
      0 var(--scroll-fade-mask-size),
      calc(100% - var(--scroll-fade-mask-size)) 100%,
      0 var(--scroll-fade-mask-size),
      calc(100% - var(--scroll-fade-mask-size)) 100%,
      0 100%,
      0 100%;
    animation-duration: 0.1s;
  }
}

@keyframes scroll-fade-top {
  from {
    --scroll-fade-top-mask-size: 0px;
  }
  to {
    --scroll-fade-top-mask-size: var(--scroll-fade-mask-size);
  }
}

@keyframes scroll-fade-bottom {
  from {
    --scroll-fade-bottom-mask-size: 0px;
  }
  to {
    --scroll-fade-bottom-mask-size: var(--scroll-fade-mask-size);
  }
}

@keyframes scroll-fade-left {
  from {
    --scroll-fade-left-mask-size: 0px;
  }
  to {
    --scroll-fade-left-mask-size: var(--scroll-fade-mask-size);
  }
}

@keyframes scroll-fade-right {
  from {
    --scroll-fade-right-mask-size: 0px;
  }
  to {
    --scroll-fade-right-mask-size: var(--scroll-fade-mask-size);
  }
}

@keyframes scroll-fade-has-block-scroll {
  from,
  to {
    --scroll-fade-block-scrollbar-size: var(--scroll-fade-scrollbar-size);
  }
}

@keyframes scroll-fade-has-inline-scroll {
  from,
  to {
    --scroll-fade-inline-scrollbar-size: var(--scroll-fade-scrollbar-size);
  }
}
